import{_ as t,c as a,o as e,a4 as r}from"./chunks/framework.I1cCAST3.js";const b=JSON.parse('{"title":"隐私政策","description":"","frontmatter":{},"headers":[],"relativePath":"docs/privacy/policy/index.md","filePath":"docs/privacy/policy/index.md"}'),o={name:"docs/privacy/policy/index.md"},d=r('<h1 id="隐私政策" tabindex="-1">隐私政策 <a class="header-anchor" href="#隐私政策" aria-label="Permalink to &quot;隐私政策&quot;">​</a></h1><p>Chaterm 收集匿名使用数据以改进产品。你的代码、提示词和对话内容绝不会被收集。</p><h2 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to &quot;概述&quot;">​</a></h2><p>Chaterm 使用 <a href="https://posthog.com" target="_blank" rel="noreferrer">PostHog</a>（一个开源分析平台）收集和分析匿名使用数据。这个反馈循环帮助团队了解开发者如何使用产品，并指导功能和用户体验的改进。</p><p>我们的遥测实现是完全透明的 —— 你可以查看<a href="https://github.com/chaterm/Chaterm" target="_blank" rel="noreferrer">源代码</a>以确切了解我们跟踪的内容。</p><div class="info custom-block"><p class="custom-block-title">透明度</p><p>所有收集的数据在离开你的设备之前都经过匿名化处理，不包含任何个人身份信息（PII）。你可以随时在公开仓库中审计遥测实现。</p></div><h2 id="我们跟踪什么" tabindex="-1">我们跟踪什么 <a class="header-anchor" href="#我们跟踪什么" aria-label="Permalink to &quot;我们跟踪什么&quot;">​</a></h2><p>我们收集基本的匿名使用数据，包括：</p><table tabindex="0"><thead><tr><th>类别</th><th>示例</th></tr></thead><tbody><tr><td><strong>任务交互</strong></td><td>任务的开始和结束时间、对话流程（不含内容）</td></tr><tr><td><strong>模式与工具使用</strong></td><td>所选的 AI 模式、调用的工具</td></tr><tr><td><strong>令牌使用量</strong></td><td>用于成本估算的对话长度指标（不包含令牌的实际内容）</td></tr><tr><td><strong>用户界面活动</strong></td><td>各界面功能的使用情况</td></tr></tbody></table><h2 id="如何退出" tabindex="-1">如何退出 <a class="header-anchor" href="#如何退出" aria-label="Permalink to &quot;如何退出&quot;">​</a></h2><p>遥测功能完全是可选的：</p><ul><li>当你首次安装或更新 Chaterm 时，会显示关于匿名遥测的通知。</li><li>你可以随时在隐私设置页面更改偏好。</li></ul><p>有关数据收集、脱敏和同步的完整控制，请参阅<a href="/docs/privacy/settings/">隐私设置</a>。</p>',13),s=[d];function i(n,c,l,h,p,_){return e(),a("div",null,s)}const f=t(o,[["render",i]]);export{b as __pageData,f as default};
